lessons:[
{num:1,topic:"Energy Overview",subtopics:"Forms of energy, energy in everyday life",objectives:"Identify and describe different forms of energy in everyday contexts.",inquiry:"What are the forms of energy we use daily?",content:"Energy exists in many forms: kinetic (movement), gravitational potential (height), thermal (heat), chemical (fuels, food, batteries), elastic (stretched springs), electrical (current in circuits), light (radiant), sound (vibrations), nuclear (atoms), and magnetic. Energy is not a 'thing' you can hold — it's a quantity that describes the capacity to cause change. Everything that happens involves energy transfer or transformation. Students brainstorm all the energy they've used since waking up: alarm clock (electrical→sound), breakfast (chemical→thermal→chemical in body), walking to school (chemical→kinetic), lights (electrical→light+thermal). This reveals how dependent modern life is on energy.",
activities:["Energy audit of your morning — trace every energy use from alarm to arrival at school","Energy sorting game — classify 20 scenarios by energy form","Brainstorming chart: what forms of energy are in this room right now?"],
experiment:null,simulation:{title:"Energy Form Identifier",desc:"Interactive scenes (kitchen, playground, factory). Students click on objects to reveal the energy forms present. Score points for finding all forms in each scene."},
formative:"Exit ticket: list 5 forms of energy with one real example of each.",
differentiation:{support:"Energy forms poster with images for each type.",extend:"Identify unusual examples: what form of energy does a compressed gas have? A moving magnetic field? A hot cup of tea in terms of ALL its energy forms?"},phase:"Engage"},

{num:2,topic:"Energy Transfers and Transformations",subtopics:"Energy conversion chains, conservation preview",objectives:"Describe energy transformations with examples. Draw energy chain diagrams.",inquiry:"How does energy change form?",content:"Energy transfers: energy moves from one object to another (hot coffee warms your hands — thermal energy transfers from coffee to hands). Energy transformations: energy changes from one form to another within a system (a torch: chemical→electrical→light+thermal). Energy chains show the sequence of transformations: coal power station: chemical (coal) → thermal (burning) → kinetic (steam/turbine) → electrical (generator) → light+thermal (your lamp). At every step, some energy becomes thermal energy that dissipates — this is 'wasted' energy. The total energy is always conserved (never created or destroyed), but the useful proportion decreases at each step.",
activities:["Energy conversion chart: for 10 devices, draw the energy chain from source to useful output + waste","Everyday device analysis: pick 3 devices in the room, trace the complete energy chain from original source (Sun/fossil fuel/nuclear) to final use","Human energy chain: food (chemical) → digestion (thermal+chemical) → muscles (kinetic) → climbing stairs (gravitational PE). Calculate the efficiency!"],
experiment:null,simulation:null,
formative:"Flowchart: draw energy conversion chains for 5 devices, identifying useful output and waste at each step.",
differentiation:{support:"Sentence starters: 'In a [device], [form] energy is converted to [form] energy...'",extend:"Draw the complete energy chain from the Sun to the light in your room, including ALL intermediate steps (Sun→plant→coal→power station→grid→lamp). How many transformations?"},phase:"Explore"},

{num:3,topic:"Energy Flow Diagrams — Sankey Diagrams",subtopics:"Quantitative energy flow, reading and drawing Sankey diagrams",objectives:"Interpret and draw Sankey diagrams showing energy inputs, useful outputs, and waste.",inquiry:"How efficient are devices in using energy?",content:"Sankey diagrams are arrow diagrams where the WIDTH of each arrow is proportional to the amount of energy. The input arrow enters from the left. It splits into: useful output (continues forward) and wasted energy (branches off, usually downward). The total width of output arrows MUST equal the input arrow width (conservation of energy). Example: incandescent bulb — 100J input → 10J light (useful, thin arrow forward) + 90J thermal (waste, thick arrow downward). The bulb is only 10% efficient — the Sankey diagram makes this dramatically visible. LED: 100J → 40J light + 60J thermal — visibly more of the arrow goes to useful output. Students draw Sankey diagrams from given data and extract data from given Sankey diagrams.",
activities:["Build Sankey diagrams from scenarios: given input energy and useful output, calculate waste and draw to scale","Interpret pre-drawn Sankey diagrams: extract efficiency, useful output, and waste values","Compare Sankey diagrams for incandescent vs CFL vs LED — which is visually most efficient?"],
experiment:null,simulation:{title:"Sankey Diagram Builder",desc:"Students input energy values and the tool draws proportional Sankey diagrams automatically. They can compare devices side by side and see efficiency differences visually."},
formative:"Worksheet: draw Sankey diagrams for 4 devices from given data. Extract efficiency from 2 pre-drawn diagrams.",
differentiation:{support:"Pre-made templates with the input arrow drawn — students split it proportionally.",extend:"Draw a multi-stage Sankey: power station (40% efficient) → transmission (95%) → appliance (80%). Show the cascading losses. Calculate overall efficiency."},phase:"Explain"},

{num:4,topic:"Efficiency",subtopics:"Useful vs wasted energy, efficiency formula, improving efficiency",objectives:"Calculate energy efficiency. Compare the efficiency of different devices.",inquiry:"What does energy efficiency mean?",content:"Efficiency = (useful energy output ÷ total energy input) × 100%. A device that converts 30J of 100J input into useful output is 30% efficient — 70% is wasted (usually as thermal energy). No device is 100% efficient because friction, air resistance, electrical resistance, and sound always convert some energy to waste heat. Comparing: petrol car engine ~25%, diesel ~35%, electric motor ~85-95%, human body ~25%, coal power station ~35%, solar panel ~20%, LED ~40%, incandescent bulb ~10%. The huge range shows why technology choice matters for sustainability. Improving efficiency: better insulation, streamlining, lubrication, using LEDs instead of incandescent, regenerative braking in electric cars.",
activities:["Efficiency wheel challenge: calculate efficiency for 8 devices from given input/output data","Appliance comparison: research and compare star ratings of appliances — what does each star save?","Quick quiz: efficiency formula use — calculate efficiency, useful output, or total input from given values"],
experiment:{title:"Measuring Efficiency of a Pulley System",aim:"Compare input work with output work in a pulley system to calculate mechanical efficiency.",
equipment:["Single and double pulley systems","Newton meter","Masses (200g, 500g)","Metre ruler","String","Clamp stand"],
method:["Set up a single pulley. Attach a 500g mass (load). Pull the string with a Newton meter to lift the load at constant speed.","Record: pulling force (F_pull), distance pulled (d_pull), load weight (W = mg), height lifted (h).","Calculate: input work = F_pull × d_pull. Output work = W × h. Efficiency = output/input × 100%.","Repeat with a double pulley system. Compare efficiencies.","Repeat with different loads. Plot efficiency vs load for each system."],
safety:"Secure the clamp stand. Don't let masses fall on feet. Use a smooth pulling motion.",
results:"Single pulley: ~80-90% efficient (friction at the axle). Double pulley: ~60-75% (more friction from additional pulley). Efficiency decreases slightly with heavier loads. The 'lost' energy goes to thermal energy at the friction points — you can feel the pulley getting slightly warm.",
criterionLink:"C (data processing, efficiency calculation, comparison)"},
simulation:null,formative:"Quick quiz: efficiency formula calculations — find efficiency, useful output, or total input.",
differentiation:{support:"Provide the efficiency formula triangle. Use whole-number values.",extend:"Calculate cumulative efficiency: if 3 devices in a chain are each 80% efficient, overall = 0.8³ = 51.2%. Discuss implications for long energy chains."},phase:"Explain"},

{num:5,topic:"Comparing Energy Sources",subtopics:"Renewable vs non-renewable, advantages and disadvantages",objectives:"Classify energy sources as renewable or non-renewable. Compare their advantages and disadvantages.",inquiry:"What are the benefits and drawbacks of each energy type?",content:"Non-renewable: will eventually run out. Coal, oil, natural gas (fossil fuels — formed over millions of years from ancient organisms), uranium (nuclear fission). Renewable: replenished naturally within a human lifetime. Solar, wind, hydroelectric, tidal, wave, geothermal, biomass. Key comparison criteria: CO₂ emissions (fossil fuels: high. Nuclear/renewables: low during operation), reliability (fossil/nuclear: 24/7 baseload. Solar/wind: intermittent — depends on weather), cost (fossil: cheap fuel but environmental costs. Renewables: high upfront but free fuel), environmental impact (all have some — dams flood valleys, wind farms affect birds, solar farms use land, nuclear creates radioactive waste).",
activities:["Energy source card sort: classify 12 sources, list 2 advantages and 2 disadvantages for each","Renewable/non-renewable debate: structured debate on 'Should we ban all fossil fuels by 2040?'","Sort-and-classify activity: rank sources by CO₂, reliability, cost, and land use"],
experiment:{title:"Solar Panel Output Investigation",aim:"Investigate how the angle of a solar panel relative to a light source affects its electrical output.",
equipment:["Small solar panel","Multimeter (to measure voltage and current)","Desk lamp (or use sunlight)","Protractor","Connecting wires","Ruler"],
method:["Set up the solar panel at a fixed distance from the lamp.","Angle the panel at 0° (flat), 15°, 30°, 45°, 60°, 75°, 90° relative to the light.","At each angle: measure voltage (V) and current (I). Calculate power = V × I.","Record 3 readings at each angle. Calculate mean power.","Plot power vs angle. Identify the optimal angle.","Discuss: how does this relate to the latitude of your location and the angle of the Sun?"],
safety:"Don't stare at the lamp. Handle the solar panel carefully.",
results:"Maximum output when the panel directly faces the light source (perpendicular). Output decreases with angle because less light hits the panel surface. The optimal angle in real installations equals the latitude of the location (to face the Sun most directly on average).",
criterionLink:"B (variables, method), C (data, graph, optimal angle)"},
simulation:null,formative:"Sort-and-classify activity: rank energy sources by 4 criteria.",
differentiation:{support:"Source visuals with key facts on cards for sorting.",extend:"Research newer sources: hydrogen fuel cells, tidal lagoons, thorium reactors, space-based solar. Compare with existing options."},phase:"Explore"},

{num:6,topic:"Fossil Fuels",subtopics:"Coal, oil, natural gas — formation, use, environmental impact",objectives:"Explain how fossil fuels formed and are used. Describe their environmental impacts.",inquiry:"Why are fossil fuels still used despite their harmful effects?",content:"Fossil fuels formed over 300 million years from the remains of ancient organisms. Coal: from swamp plants buried and compressed. Oil and gas: from marine organisms buried under sediment on the ocean floor. They store chemical energy from ancient sunlight (photosynthesis captured solar energy → stored as chemical energy in organisms → buried → compressed → fossil fuel). Burning releases this energy as heat: fuel + oxygen → CO₂ + H₂O + energy. Problems: CO₂ is a greenhouse gas (traps infrared radiation → enhanced greenhouse effect → global warming). Also produces SO₂ (acid rain), NOₓ (smog), and particulates (health problems). Despite this, fossil fuels provide ~80% of global energy because they're energy-dense, reliable, cheap (excluding environmental costs), and existing infrastructure is built around them. Transitioning away requires replacing not just the fuel but the entire system.",
activities:["Carbon journey comic strip: draw the journey of a carbon atom from ancient forest → coal → power station → atmosphere → ocean","Fossil fuel timeline: how long to form vs how long to use up?","Worksheet: fossil fuel environmental impact — match each pollutant to its effect"],
experiment:null,simulation:null,formative:"Worksheet: describe formation, use, and 3 environmental impacts of fossil fuels.",
differentiation:{support:"Comic strip template with prompts at each stage.",extend:"Research the carbon cycle in detail. How much CO₂ do oceans absorb? What happens when they absorb too much? (Ocean acidification.)"},phase:"Explain"},

{num:7,topic:"Renewable Energy — Solar, Wind, Hydro",subtopics:"How each works, advantages, limitations",objectives:"Describe how solar, wind, and hydroelectric energy are captured and converted to electricity.",inquiry:"How does nature provide us with energy?",content:"Solar: photovoltaic (PV) cells convert sunlight directly to electricity (photons knock electrons free in silicon). Solar thermal: mirrors concentrate sunlight to heat water → steam → turbine. Advantages: no CO₂, free fuel, modular. Limitations: intermittent (night, clouds), expensive panels, large area needed. Wind: wind turns turbine blades → generator → electricity. Advantages: no CO₂, free fuel, can be offshore. Limitations: intermittent (calm days), visual impact, noise, bird strikes. Hydroelectric: water stored behind a dam falls through turbines → generator. Advantages: reliable (water stored = energy stored), no CO₂, long lifespan, can respond quickly to demand. Limitations: floods valleys (habitat destruction), displaces communities, silting, only works where geography allows. All three ultimately derive from solar energy: the Sun heats air (wind), evaporates water (rain fills reservoirs), and directly provides light (solar panels).",
activities:["Interactive renewable stations: research one source per group, present to class","Gallery walk: visit each group's presentation, fill in a comparison sheet","Build a mini wind turbine from card — test different blade designs"],
experiment:{title:"Wind Turbine Blade Design",aim:"Investigate how blade number and angle affect the electrical output of a model wind turbine.",
equipment:["Small DC motor used as generator","Card/plastic for blades","Fan as wind source","Multimeter","Protractor","Scissors, tape"],
method:["Build turbine blades from card. Attach to the motor shaft.","Place the fan at a fixed distance (constant wind speed).","Test: 2 blades, 3 blades, 4 blades, 6 blades. Measure voltage output for each.","Test: blade angle at 15°, 30°, 45°, 60° from the rotation plane. Measure voltage for each.","3 trials per configuration. Calculate mean.","Plot output vs blade number and output vs blade angle. Identify optimal design."],
safety:"Keep fingers away from spinning blades. Secure the fan.",
results:"Typically 3-4 blades at ~30-45° angle gives maximum output. Too few blades miss wind; too many create turbulence. Too flat an angle means less wind push; too steep means too much drag. Real wind turbines use 3 blades at carefully calculated angles.",
criterionLink:"B (design, variables), C (data comparison, optimisation)"},
simulation:null,formative:"Gallery walk reflection sheet: compare 3 renewable sources across 5 criteria.",
differentiation:{support:"Video explanations of each source before group work.",extend:"Research: why do real wind turbines have exactly 3 blades? What's the physics behind this choice?"},phase:"Explore"},

{num:8,topic:"Solar Energy Focus",subtopics:"Solar panels, active vs passive solar heating",objectives:"Explain how solar energy is captured for electricity and heating. Compare active and passive solar systems.",inquiry:"How does solar heating differ from solar electricity?",content:"Two ways to use solar energy. Solar PV (electricity): semiconductor cells (usually silicon) convert photons directly to electrical current. Each cell produces ~0.5V. Cells are connected in series for higher voltage. Efficiency: 15-22% (most sunlight becomes heat, not electricity). Solar thermal (heating): dark surfaces absorb sunlight → heat water or air. Passive solar: building design that maximises solar gain (large south-facing windows, thermal mass to store heat, overhangs to shade in summer). Active solar: pumped systems that circulate water through roof panels to heat a tank. Solar cookers use reflective surfaces to concentrate sunlight onto a cooking pot — used in developing countries where fuel is scarce. The key physics: dark, matte surfaces absorb more radiation than light, shiny surfaces (which reflect it).",
activities:["Mini solar cooker design: build a solar cooker from cardboard, foil, and plastic wrap. Test by heating water in sunlight.","Design journal: sketch a solar-heated house — label south-facing windows, thermal mass, overhangs, insulation","Investigate: does the colour of a surface affect how much solar energy it absorbs? (Heat water in black vs white vs silver containers in sunlight.)"],
experiment:{title:"Solar Heating — Surface Colour Investigation",aim:"Investigate how surface colour affects the rate of solar heating.",
equipment:["3 identical containers (tin cans)","Black paint, white paint, shiny foil","Thermometers","Sunlight or desk lamps","Stopwatch","Water (equal volumes)"],
method:["Paint one can black, one white, wrap one in foil.","Fill each with equal volumes of water at the same starting temperature.","Place all three in direct sunlight (or equal distance from identical lamps).","Record temperature every 2 minutes for 20 minutes.","Plot temperature vs time for all three on the same axes.","Calculate the temperature rise for each. Rank by heating rate."],
safety:"Handle hot containers with care. Don't stare at bright lamps.",
results:"Black can heats fastest (absorbs most radiation). White can heats slowest (reflects most). Foil reflects most and heats very slowly. This explains why solar water heaters use black-coated collectors and why light-coloured clothing is cooler in summer.",
criterionLink:"B (fair test), C (graph, comparison, explanation)"},
simulation:null,formative:"Design journal entry: sketch a solar-powered device and explain the physics.",
differentiation:{support:"Templates for the solar cooker design with measurements.",extend:"Research real solar thermal power stations (concentrated solar power — CSP). How do mirrors focus sunlight? Calculate the temperature achievable."},phase:"Elaborate"},

{num:9,topic:"Wind and Hydro Energy",subtopics:"Wind turbines, hydroelectric dams, mechanisms and comparisons",objectives:"Compare the mechanisms and efficiency of wind and hydroelectric energy generation.",inquiry:"How does wind move machines? How does water generate electricity?",content:"Wind turbines: wind (kinetic energy of air) → blades rotate (kinetic) → generator (electrical). Power available in wind ∝ v³ (doubling wind speed gives 8× more power!). This is why turbine location matters enormously. Offshore wind is stronger and more consistent than onshore. Modern turbines: 100m+ blade diameter, 5-15 MW each. Capacity factor: ~30-40% (wind doesn't blow at rated speed all the time). Hydroelectric: water stored at height (GPE) → falls through pipes → turns turbines (kinetic) → generator (electrical). Energy available = mgh. Pumped storage: pump water uphill when electricity is cheap (night), let it flow down when demand is high (peak). This is currently the best large-scale energy storage technology. Comparison: hydro is more reliable (water can be stored) but more environmentally destructive (flooding). Wind has less environmental impact but is intermittent.",
activities:["Generator demonstration: spin a hand-crank generator — feel the resistance increase when you connect a load (the generator is harder to turn when producing electricity)","Compare: wind vs hydro across 6 criteria (reliability, cost, environmental impact, efficiency, scalability, location requirements)","Exit ticket: compare two energy sources using data"],
experiment:null,simulation:null,formative:"Exit ticket: compare wind and hydro energy across reliability, cost, and environmental impact.",
differentiation:{support:"Comparison table template with criteria pre-filled.",extend:"Analyse power output graphs for a wind farm over a week. Calculate the capacity factor. Discuss the implications for grid reliability."},phase:"Explain"},

{num:10,topic:"Environmental Impact of Energy",subtopics:"Pollution, land use, habitat destruction, climate change",objectives:"Identify and evaluate the environmental impacts of different energy sources.",inquiry:"How does energy production affect the environment?",content:"Every energy source has environmental impacts. Fossil fuels: CO₂ (climate change), SO₂ (acid rain), NOₓ (smog), particulates (lung disease), oil spills, mining damage. Nuclear: radioactive waste (hazardous for 100,000+ years), accident risk (Chernobyl, Fukushima), thermal pollution of waterways, uranium mining. Hydroelectric: valley flooding, habitat destruction, fish migration blocked, downstream ecosystem changes, methane from submerged vegetation. Wind: bird/bat deaths, noise pollution, visual impact on landscapes, manufacturing uses rare earth metals. Solar: land use (large farms), manufacturing uses toxic chemicals, disposal of old panels. Biomass: deforestation risk, competes with food production, still produces CO₂. The key insight: there's no 'perfect' energy source. Every choice involves trade-offs. Informed decisions require understanding ALL the impacts, not just the obvious ones.",
activities:["Oil spill simulation: pour cooking oil on water. Try to clean it up with different methods (skimming, absorbing with cotton, detergent). Discuss the difficulty and environmental damage.","Environmental impact comparison chart: for 6 sources, rate impact on air, water, land, wildlife, and climate (1-5 scale)","Land use pie chart: compare the land area needed to generate 1 GW from different sources"],
experiment:null,simulation:null,formative:"Compare environmental costs worksheet: rate 6 sources across 5 impact categories.",
differentiation:{support:"Sentence frames for describing impacts.",extend:"Research and present one energy disaster in detail (Deepwater Horizon, Chernobyl, Banqiao Dam, etc.). Explain the physics of what went wrong."},phase:"Elaborate"},

{num:11,topic:"Energy in Our Homes",subtopics:"Household energy use, energy audits, reducing consumption",objectives:"Analyse household energy use patterns and suggest practical ways to reduce energy consumption.",inquiry:"How can we reduce energy use in daily life?",content:"Average household energy breakdown (varies by climate): heating/cooling ~40%, water heating ~18%, appliances ~15%, lighting ~10%, cooking ~5%, electronics ~5%, other ~7%. The biggest savings come from the biggest uses. Reducing heating: insulation (loft, cavity wall, double glazing), draught-proofing, smart thermostats, lower thermostat settings (each 1°C reduction saves ~10% of heating energy). Reducing electricity: LED lighting (uses 1/6 the energy of incandescent), efficient appliances (5-star rated), turning off standby (standby power can be 5-10% of a home's electricity), using timers and sensors. Students conduct a simplified energy audit: list all energy-using devices, estimate hours of use, calculate daily kWh consumption, identify the biggest consumers, and propose specific reductions with calculated savings.",
activities:["Home energy survey: list every energy-using device at home, estimate daily usage hours","Light audit: count all light bulbs at home, note wattage, calculate daily lighting energy","Energy saving checklist: rate your home's efficiency and identify 5 improvements with estimated savings"],
experiment:null,simulation:{title:"Home Energy Simulator",desc:"Virtual house where students can add/remove insulation, change bulbs, adjust heating, add solar panels. Total energy use and cost update in real-time. Students try to achieve the lowest energy bill."},
formative:"Energy saving checklist submission with 5 specific proposals and estimated savings.",
differentiation:{support:"Guided survey template with example calculations filled in.",extend:"Calculate the annual cost of energy for your home. Propose 3 improvements. Calculate payback time for each (cost of improvement ÷ annual saving)."},phase:"Explore"},

{num:12,topic:"Energy Around the World",subtopics:"Energy poverty, access disparity, development and energy",objectives:"Describe global energy access inequalities. Discuss the relationship between energy access and development.",inquiry:"Why do some countries have less access to energy?",content:"770 million people worldwide lack electricity. 2.4 billion rely on burning wood, charcoal, or dung for cooking — causing indoor air pollution that kills ~4 million people per year. Energy poverty correlates strongly with economic poverty, limited education access, poor healthcare, and lower life expectancy. The energy inequality: the average American uses ~300 kWh/day; the average person in sub-Saharan Africa uses ~2 kWh/day. Historical context: wealthy nations industrialised using fossil fuels over 200 years. Now, developing nations are told to skip fossil fuels and go straight to renewables — which are often more expensive upfront. This raises profound fairness questions. Solutions being explored: off-grid solar for rural areas (solar home systems), micro-hydro for villages, improved cookstoves, mobile-money-based pay-as-you-go solar, and international climate finance.",
activities:["Global energy map analysis: study a world map of per-capita energy consumption. Identify patterns. Discuss causes.","World Bank data charts: compare energy access, GDP, and life expectancy for 10 countries. Identify correlations.","Case study comparison: life with and without electricity — a day in two different villages"],
experiment:null,simulation:null,formative:"Case study comparison: present two communities' energy situations with analysis.",
differentiation:{support:"Key terms glossary for energy poverty terminology.",extend:"Research one real off-grid solar project in a developing country. How does it work? What difference has it made? Present findings."},phase:"Explain"},

{num:13,topic:"Sustainability Concepts",subtopics:"Conservation, sustainable living, ecological footprint",objectives:"Explain what makes energy use sustainable. Evaluate personal and national ecological footprints.",inquiry:"What makes energy use sustainable?",content:"Sustainable energy use means meeting current needs without compromising future generations' ability to meet theirs. Three pillars: environmental (not depleting resources or damaging ecosystems), economic (affordable and supporting development), social (equitable access, not harming communities). Ecological footprint: the area of land/sea needed to support a person's lifestyle. The global average is ~2.7 hectares per person — but Earth can sustainably provide only ~1.7 hectares. We're using 1.6 Earths. Wealthiest nations' footprints are 4-5× the sustainable level. Reducing footprint: energy efficiency, renewable energy, reduced consumption, better transport choices, dietary changes (meat production uses 10× more energy than plant-based food). The concept of 'circular economy': design products so materials are reused/recycled, waste becomes input for other processes, energy comes from renewable sources.",
activities:["Sustainability wheel: evaluate energy use across environmental, economic, and social dimensions","Online ecological footprint calculator: calculate your personal footprint. Compare with global sustainable level.","Poster design task: create a poster promoting one specific sustainable energy practice"],
experiment:null,simulation:null,formative:"Poster design with scientific justification for sustainability practices.",
differentiation:{support:"Prompt list for poster content.",extend:"Research your school's ecological footprint. Propose a specific, costed plan to reduce it by 20%."},phase:"Elaborate"},

{num:14,topic:"Carbon Footprint",subtopics:"CO₂ emissions, calculating personal carbon footprint, reduction strategies",objectives:"Calculate and evaluate personal carbon footprint. Propose evidence-based reduction strategies.",inquiry:"How can we reduce our own carbon footprint?",content:"Carbon footprint = total CO₂ (and CO₂-equivalent greenhouse gases) produced directly and indirectly by a person, organisation, or product. Major contributors for individuals: home energy (~30%), transport (~25%), food (~20%), goods and services (~15%), waste (~10%). Average carbon footprint: USA ~16 tonnes CO₂/year, UK ~6, India ~2, global average ~4.5. To limit warming to 1.5°C, we need to reach ~2 tonnes per person by 2050. Biggest personal reductions: avoid one transatlantic flight (~1.6 tonnes saved), go car-free (~2.5 tonnes), eat plant-based diet (~0.8 tonnes), switch to renewable electricity (~1.5 tonnes). But individual action alone isn't enough — systemic change (policy, infrastructure, technology) is essential. Both matter.",
activities:["Online carbon footprint calculator: calculate your personal footprint across all categories","CO₂ bar graphs: visualise the carbon footprint of different activities, foods, and transport modes","Journal entry: personal reflection on your footprint and realistic commitments to reduce it"],
experiment:null,simulation:null,formative:"Journal entry: calculated personal carbon footprint + 3 specific, realistic reduction commitments with estimated savings.",
differentiation:{support:"Structured reflection template with prompts for each section.",extend:"Calculate the class total carbon footprint. Propose a class carbon reduction plan with a target and timeline."},phase:"Elaborate"},

{num:15,topic:"Debating Energy Choices",subtopics:"Energy policy, equity, informed decision-making",objectives:"Analyse the fairness of energy decisions using scientific evidence and ethical reasoning.",inquiry:"Who should decide how energy is used?",content:"Energy policy involves complex trade-offs. Should a government invest in nuclear power? It provides reliable low-CO₂ electricity but creates radioactive waste for 100,000 years and poses accident risk. Should rich countries fund renewable energy in poor countries? It's morally strong but who controls the technology and benefits? Should carbon taxes be imposed? They discourage fossil fuel use but may disproportionately affect the poor. Students learn to construct evidence-based arguments: (1) state your position, (2) provide scientific evidence, (3) acknowledge counterarguments, (4) evaluate trade-offs, (5) reach a justified conclusion. This develops Criterion D skills: reflecting on the implications of science for society.",
activities:["Group debate on energy subsidies: should fossil fuel subsidies be redirected to renewables? Each group prepares for/against with evidence.","Peer evaluation checklist: assess each other's arguments for scientific accuracy, logical reasoning, and consideration of multiple perspectives","Policy proposal: each group proposes one energy policy change for your country, justified with data"],
experiment:null,simulation:null,formative:"Peer evaluation of debate performance using a structured checklist.",
differentiation:{support:"Debate roles guide: researcher, speaker, questioner, note-taker.",extend:"Write a formal position paper on one energy policy issue, citing at least 5 sources of evidence."},phase:"Evaluate"},

{num:16,topic:"Future Energy Solutions",subtopics:"Innovation, smart energy systems, hydrogen, fusion",objectives:"Research and evaluate emerging energy technologies.",inquiry:"What is the future of energy?",content:"Emerging technologies that could transform energy. Hydrogen fuel cells: hydrogen + oxygen → electricity + water (zero emissions). Challenges: producing 'green hydrogen' (using renewable electricity to split water) is expensive; storage is difficult (hydrogen is very light and leaks through containers). Smart grids: AI-managed electricity networks that balance supply and demand in real-time, integrate distributed generation (rooftop solar), and manage energy storage. Nuclear fusion: combining hydrogen nuclei to release enormous energy (the Sun's process). If achieved: virtually unlimited fuel (deuterium from seawater), no long-lived waste, no CO₂. ITER (France) aims for net energy gain by ~2035. Commercial fusion: possibly 2040-2050. Battery technology: lithium-ion improving rapidly (cost dropped 90% in 10 years), solid-state batteries (safer, higher density), grid-scale storage enabling 100% renewable electricity.",
activities:["Research project: choose one future energy technology. Create a presentation covering: how it works, current status, advantages, challenges, timeline to commercialisation","Presentation feedback: peer assessment using a rubric","Innovation fair: present your research to the class in a poster/presentation format"],
experiment:null,simulation:null,formative:"Presentation assessed on scientific accuracy, evidence quality, and balanced evaluation.",
differentiation:{support:"Provided research resource list with reliable sources.",extend:"Independent research on a technology not covered in the lesson. Compare with existing options using quantitative data."},phase:"Explore"},

{num:17,topic:"Circular Energy Systems",subtopics:"Reuse, feedback loops, waste-to-energy, circular economy",objectives:"Explain the concept of circular energy systems. Evaluate how waste can become a resource.",inquiry:"Can we make energy systems circular?",content:"Linear economy: extract → make → use → throw away. Circular economy: design out waste — every output becomes an input for something else. Energy examples: combined heat and power (CHP) — a power station's 'waste' heat is piped to homes for heating (increases overall efficiency from ~35% to ~80%). Waste-to-energy: burning non-recyclable waste generates electricity (better than landfill, but still produces CO₂). Biogas: decomposing organic waste produces methane → burn for electricity + heat. Industrial symbiosis: one factory's waste heat/steam is used by another factory nearby. Nature's model: ecosystems are circular — dead organisms decompose, releasing nutrients for new growth. No waste in nature. Students design a circular energy system for a hypothetical community.",
activities:["Energy loop design activity: design a circular energy system for a school — how can waste heat, food waste, and solar energy be connected?","Diagram submission: draw a closed-loop energy system with all flows labelled","Case study: Kalundborg Symbiosis (Denmark) — an industrial ecosystem where 6 companies exchange energy and waste"],
experiment:null,simulation:null,formative:"Diagram: design a circular energy system with clear energy flows and justification.",
differentiation:{support:"Template with labelled components to connect.",extend:"Research closed-loop systems in nature (ecosystem energy flow). Compare with the industrial system you designed. What can industry learn from nature?"},phase:"Explain"},

{num:18,topic:"School Energy Audit",subtopics:"Real-world energy monitoring, data collection, proposals",objectives:"Apply energy knowledge to analyse and improve real energy consumption in your school.",inquiry:"Where does our school use the most energy?",content:"Students conduct a real energy audit of their school (or a section of it). This is applied physics: measuring, calculating, evaluating, and proposing improvements based on evidence. Steps: (1) Walk through the school identifying all energy-using systems (heating, lighting, computers, kitchen, labs). (2) Estimate or measure energy consumption for each (from meter readings, appliance ratings, and usage hours). (3) Identify waste (lights left on in empty rooms, computers on standby, poor insulation, single-glazed windows). (4) Propose improvements with estimated savings. (5) Present findings to the class (or school administration). This connects directly to Criterion D: applying science to address a real-world issue.",
activities:["Energy walkthrough: survey the school with a checklist of energy use points","Data collection: record appliance types, wattage, estimated hours of use, insulation quality","Data report + action suggestions: write up findings with specific, costed recommendations"],
experiment:null,simulation:null,formative:"Data report: energy audit findings with 5 specific, costed improvement proposals.",
differentiation:{support:"Data collection sheet with pre-made categories and prompts.",extend:"Present your findings to the school's facilities manager or administration. Propose a formal energy reduction plan."},phase:"Elaborate"},

{num:19,topic:"Unit Project — Sustainable Energy Plan",subtopics:"Designing a sustainable energy plan for a home or school",objectives:"Apply all unit knowledge to propose and design a sustainable energy solution.",inquiry:"How can we apply our learning to make a difference?",content:"Summative project: students design a sustainable energy plan for their home, school, or a hypothetical community. The plan must include: (1) Current energy audit (what energy is used, how much, from what sources). (2) Proposed changes (efficiency improvements + renewable generation). (3) Calculations (energy saved, cost of improvements, payback time, CO₂ reduction). (4) Sankey diagrams (before and after). (5) Evaluation of trade-offs (cost vs benefit, practicality, aesthetics, maintenance). (6) Reflection on the broader implications (how does this connect to the Statement of Inquiry about fairness, equity, and sustainability?). This is assessed against Criterion A (knowledge) and Criterion D (reflecting on impacts).",
activities:["Project design template: structured planning document with sections for each requirement","Feedback sessions: peer review of draft plans before final submission","Project work with rubric: independent work time with teacher conferencing"],
experiment:null,simulation:null,formative:"Project submission assessed against Criteria A and D using task-specific rubric.",
differentiation:{support:"Step-by-step project guide with examples for each section.",extend:"Build a physical prototype or detailed model of one element of your plan (e.g., a solar water heater, a wind turbine, an insulation system). Test and evaluate it."},phase:"Evaluate"},

{num:20,topic:"Unit Review and Reflection",subtopics:"Key concepts, SOI connection, personal growth",objectives:"Review all unit concepts. Reflect on how energy choices impact society and the environment.",inquiry:"How have your views on energy changed through this unit?",content:"Review connecting all unit concepts: forms of energy → transfers and transformations → efficiency and Sankey diagrams → renewable vs non-renewable → environmental impacts → global energy inequality → sustainability → carbon footprint → future technologies → circular systems → real-world application (school audit + project). Return to the Statement of Inquiry: 'Energy choices affect relationships within society and the environment, raising questions of equity and sustainability.' How has your understanding of this statement deepened through the unit? Students complete a Kahoot quiz for knowledge review and a reflection journal exploring how their views on energy have changed. The reflection should reference specific evidence and experiences from the unit.",
activities:["Kahoot quiz: 20 questions covering all unit topics — competitive and fun review","Reflection journal: structured reflection on learning journey, changed perspectives, and personal commitments","Concept map: connect all key terms and concepts from the unit — minimum 20 terms with labelled relationships"],
experiment:null,simulation:null,formative:"Reflection journal + concept map submission. Summative quiz.",
differentiation:{support:"Sentence starters for reflection: 'Before this unit, I thought... Now I understand that...'",extend:"Record a class podcast episode: 10-minute discussion of the most important energy issue facing your generation. Include scientific evidence and personal perspectives."},phase:"Evaluate"}
]
